parameters.jsCode:
const data = $input.first().json;
const issueColors = {
  accepted_overdue: '#e74c3c',
  in_progress_overdue: '#e74c3c',
  invitation_no_response_5d: '#e67e22',
  delivered_pending_review_7d: '#9b59b6',
  deadline_soon_3d: '#f1c40f'
};
const issueLabels = {
  accepted_overdue: 'Aceptado pero sin entregar (deadline pasado)',
  in_progress_overdue: 'En progreso pero deadline pasado',
  invitation_no_response_5d: 'Invitacion sin respuesta > 5d',
  delivered_pending_review_7d: 'Entregado pendiente revision Damian > 7d',
  deadline_soon_3d: 'Deadline en proximos 3 dias'
};
const rows = (data.rows || []).map(r => {
  const color = issueColors[r.issue_type] || '#7f8c8d';
  const label = issueLabels[r.issue_type] || r.issue_type;
  return '<tr>' +
    '<td><span style=\"background:' + color + ';color:white;padding:3px 8px;border-radius:12px;font-size:11px\">' + label + '</span></td>' +
    '<td><b>' + r.project_name + '</b><br><small>' + r.role + '</small></td>' +
    '<td>' + r.collab_name + '<br><small style=\"color:#7f8c8d\">' + r.specialty + ' — ' + r.collab_email + '</small></td>' +
    '<td>' + r.status + '<br><small>' + r.days_since_invited + 'd desde invitacion</small></td>' +
    '<td>' + (r.deadline ? r.deadline.substring(0,10) + (r.days_to_deadline !== null ? '<br><small>' + r.days_to_deadline + 'd</small>' : '') : '—') + '</td>' +
    '<td>' + (r.fee_eur || '?') + ' EUR</td>' +
    '</tr>';
}).join('');
const html = '<h2>Colaboradores con incidencias</h2>' +
  '<p>Total: <b>' + data.issue_count + '</b>. Revisar y actualizar status (POST /webhook/collab-update).</p>' +
  '<table border=\"1\" cellpadding=\"6\" cellspacing=\"0\" style=\"border-collapse:collapse;font-family:sans-serif;font-size:13px\">' +
  '<thead><tr style=\"background:#f3f4f6\"><th>Incidencia</th><th>Proyecto/Rol</th><th>Colaborador</th><th>Estado</th><th>Deadline</th><th>Honorarios</th></tr></thead>' +
  '<tbody>' + rows + '</tbody></table>';
return [{ json: { html_body: html, count: data.issue_count } }];

